class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        int countT = 0, countF = 0;
        for (char c : answerKey) {
            if (c == 'T') {
                countT++;
            } else if (c == 'F') {
                countF++;
            }
        }
        int maxConsecutive = countT > countF ? countT : countF;
        if (maxConsecutive > k) {
            for (int i = 1; i < maxConsecutive; i++) {
                if (countT > countF) {
                    countT--;
                } else {
                    countF--;
                }
            }
        }
        return maxConsecutive;
    }
};
```

